config.script:
b = self.view.custom.browseBase
if b and "/" in b:
	self.view.custom.browseBase = b.rsplit("/", 1)[0]

try:
	if event.value['kind'] == 'folder':
		self.view.custom.browseBase = event.value['path']
except Exception:
	pass

try:
	self.view.custom.selTag = event.value['path']
	self.view.custom.status = ""
except Exception:
	pass

asset = self.view.params.assetId or "conveyor"
user = "operator"
try:
	u = self.session.props.auth.user.userName
	if u:
		user = u
except Exception:
	user = "operator"
self.view.custom.status = mira_setup.finalize(asset, self.view.custom.approved, user)
